    # All single-char equivalents of `char` under Unicode full case folding.
    # e.g. single_char_variants("s") → ["S", "s", "ſ"]
    #      single_char_variants("ß") → ["ß", "ẞ"]
    def self.single_char_variants(char)
      fold_key = char.downcase(:fold)
      (FOLD_GROUPS[fold_key] || [char]).select { |c| c.length == 1 }.uniq
    end

    # Single-char strings whose full fold equals the fold of multi-char `str`.
    # e.g. sequence_single_char_variants("ss") → ["ß", "ẞ"]
    # Returns [] for single-char input (use single_char_variants instead).
    def self.sequence_single_char_variants(str)
      return [] if str.chars.length <= 1
      fold_key = str.downcase(:fold)
      (FOLD_GROUPS[fold_key] || []).select { |c| c.length == 1 }.uniq
    end

    # Single-char strings that fold to an already-computed fold_key.
    # e.g. single_char_variants_for_fold("st") → ["ﬆ", "ﬅ"]
    def self.single_char_variants_for_fold(fold_key)
      (FOLD_GROUPS[fold_key] || []).select { |c| c.length == 1 }.uniq
    end
  end
